fn verify_scalar_result(
    ctx: &Context,
    op: Ptr<Operation>,
    name: &str,
    width: u32,
) -> Result<(), Error> {
    let op = op.deref(ctx);
    let ty = op.get_result(0).get_type(ctx);
    let ty_object = ty.deref(ctx);
    let Some(integer) = ty_object.downcast_ref::<IntegerType>() else {
        return verify_err!(op.loc(), "{} result must be an integer", name);
    };
    if integer.width() != width {
        return verify_err!(op.loc(), "{} result must be a {}-bit integer", name, width);
    }
    Ok(())
}

